public static AnnotationMap merge(AnnotationMap primary, AnnotationMap secondary)
    {
        if (primary == null || primary._annotations == null || primary._annotations.isEmpty()) {
            return secondary;
        }
        if (secondary == null || secondary._annotations == null || secondary._annotations.isEmpty()) {
            return primary;
        }
        HashMap<Class<?>,Annotation> annotations = new HashMap<>();
        // add secondary ones first
        for (Annotation ann : secondary._annotations.values()) {
            annotations.put(ann.annotationType(), ann);
        }
        // to be overridden by primary ones
        for (Annotation ann : primary._annotations.values()) {
            annotations.put(ann.annotationType(), ann);
        }
        return new AnnotationMap(annotations);
    }

public final TypeAdapter<T> nullSafe() {
  if (!(this instanceof TypeAdapter.NullSafeTypeAdapter)) {
    return new NullSafeTypeAdapter();
  }
  return this;
}

private final class NullSafeTypeAdapter extends TypeAdapter<T> {
  @Override
  public void write(JsonWriter out, T value) throws IOException {
    if (value == null) {
      out.nullValue();
    } else {
      TypeAdapter.this.write(out, value);
    }
  }

  @Override
  public T read(JsonReader reader) throws IOException {
    if (reader.peek() == JsonToken.NULL) {
      reader.nextNull();
      return null;
    }
    return TypeAdapter.this.read(reader);
  }

  @Override
  public String toString() {
    return "NullSafeTypeAdapter[" + TypeAdapter.this + "]";
  }
}

public static Type canonicalize(Type type) {
  if (type instanceof Class) {
    Class<?> c = (Class<?>) type;
    return c.isArray() ? new GenericArrayTypeImpl(canonicalize(c.getComponentType())) : c;

  } else if (type instanceof ParameterizedType) {
    ParameterizedType p = (ParameterizedType) type;
    return new ParameterizedTypeImpl(
        p.getOwnerType(), (Class<?>) p.getRawType(), p.getActualTypeArguments());

  } else if (type instanceof GenericArrayType) {
    GenericArrayType g = (GenericArrayType) type;
    return new GenericArrayTypeImpl(g.getGenericComponentType());

  } else if (type instanceof WildcardType) {
    WildcardType w = (WildcardType) type;
    return new WildcardTypeImpl(w.getUpperBounds(), w.getLowerBounds());

  } else {
    // unsupported type, return as is
    return type;
  }
}

ParameterizedTypeImpl(Type ownerType, Class<?> rawType, Type... typeArguments) {
  requireNonNull(rawType);

  if (ownerType == null && requiresOwnerType(rawType)) {
    throw new IllegalArgumentException("Must specify owner type for " + rawType);
  }

  this.ownerType = ownerType == null ? null : canonicalize(ownerType);
  this.rawType = canonicalize(rawType);
  this.typeArguments = typeArguments.clone();
  for (int t = 0, length = this.typeArguments.length; t < length; t++) {
    requireNonNull(this.typeArguments[t]);
    checkNotPrimitive(this.typeArguments[t]);
    this.typeArguments[t] = canonicalize(this.typeArguments[t]);
  }
}

private static ObjectConstructor<? extends Collection<?>> newCollectionConstructor(
    Class<?> rawType) {

  // First try List implementation
  if (rawType.isAssignableFrom(ArrayList.class)) {
    return ArrayList::new;
  }
  // Then try Set implementation
  else if (rawType.isAssignableFrom(LinkedHashSet.class)) {
    return LinkedHashSet::new;
  }
  // Then try SortedSet / NavigableSet implementation
  else if (rawType.isAssignableFrom(TreeSet.class)) {
    return TreeSet::new;
  }
  // Then try Queue implementation
  else if (rawType.isAssignableFrom(ArrayDeque.class)) {
    return ArrayDeque::new;
  }

  // Was unable to create matching Collection constructor
  return null;
}

private String keyToString(JsonElement keyElement) {
  if (keyElement.isJsonPrimitive()) {
    JsonPrimitive primitive = keyElement.getAsJsonPrimitive();
    if (primitive.isNumber()) {
      return String.valueOf(primitive.getAsNumber());
    } else if (primitive.isBoolean()) {
      return Boolean.toString(primitive.getAsBoolean());
    } else if (primitive.isString()) {
      return primitive.getAsString();
    } else {
      throw new AssertionError();
    }
  } else if (keyElement.isJsonNull()) {
    return "null";
  } else {
    throw new AssertionError();
  }
}

public T read(JsonReader in) throws IOException {
  if (deserializer == null) {
    return delegate().read(in);
  }
  JsonElement value = Streams.parse(in);
  if (nullSafe && value.isJsonNull()) {
    return null;
  }
  return deserializer.deserialize(value, typeToken.getType(), context);
}

@Override
public void write(JsonWriter out, T value) throws IOException {
  if (serializer == null) {
    delegate().write(out, value);
    return;
  }
  if (nullSafe && value == null) {
    out.nullValue();
    return;
  }
  JsonElement tree = serializer.serialize(value, typeToken.getType(), context);
  Streams.write(tree, out);
}

@SuppressWarnings("MixedMutabilityReturnType")
  private List<String> getFieldNames(Field f) {

    String fieldName;
    List<String> alternates;
    SerializedName annotation = f.getAnnotation(SerializedName.class);
    if (annotation == null) {
      fieldName = fieldNamingPolicy.translateName(f);
      alternates = fieldNamingPolicy.alternateNames(f);
    } else {
      fieldName = annotation.value();
      alternates = Arrays.asList(annotation.alternate());
    }

    if (alternates.isEmpty()) {
      return Collections.singletonList(fieldName);
    }

    List<String> fieldNames = new ArrayList<>(alternates.size() + 1);
    fieldNames.add(fieldName);
    fieldNames.addAll(alternates);
    return fieldNames;
  }

private Hasher putBytesInternal(ByteBuffer readBuffer) {
  // If we have room for all of it, this is easy
  if (readBuffer.remaining() <= buffer.remaining()) {
    buffer.put(readBuffer);
    munchIfFull();
    return this;
  }

  // First add just enough to fill buffer size, and munch that
  int bytesToCopy = bufferSize - buffer.position();
  for (int i = 0; i < bytesToCopy; i++) {
    buffer.put(readBuffer.get());
  }
  munch(); // buffer becomes empty here, since chunkSize divides bufferSize

  // Now process directly from the rest of the input buffer
  while (readBuffer.remaining() >= chunkSize) {
    process(readBuffer);
  }

  // Finally stick the remainder back in our usual buffer
  buffer.put(readBuffer);
  return this;
}

