@SuppressWarnings("CatchingUnchecked") // sneaky checked exception
  private static String lenientToString(@Nullable Object o) {
    if (o == null) {
      return "null";
    }
    try {
      return o.toString();
    } catch (Exception e) { // sneaky checked exception
      // Default toString() behavior - see Object.toString()
      String objectToString =
          o.getClass().getName() + '@' + Integer.toHexString(System.identityHashCode(o));
      // Logger is created inline with fixed name to avoid forcing Proguard to create another class.
      Logger.getLogger("com.google.common.base.Strings")
          .log(WARNING, "Exception during lenientFormat for " + objectToString, e);
      return "<" + objectToString + " threw " + e.getClass().getName() + ">";
    }
  }

public static final boolean isContiguous(ReadablePartial partial) {
    if (partial == null) {
        throw new IllegalArgumentException("Partial must not be null");
    }
    DurationFieldType lastType = null;
    for (int i = 0; i < partial.size(); i++) {
        DateTimeField loopField = partial.getField(i);
        if (i > 0) {
            if (loopField.getRangeDurationField() == null || loopField.getRangeDurationField().getType() != lastType) {
                return false;
            }
        }
        lastType = loopField.getDurationField().getType();
    }
    return true;
}

public static List<Throwable> findNestedThrowables(Throwable rootThrowable) {
	Preconditions.notNull(rootThrowable, "Throwable must not be null");

	Set<Throwable> visited = new LinkedHashSet<>();
	Deque<Throwable> toVisit = new ArrayDeque<>();
	toVisit.add(rootThrowable);

	while (!toVisit.isEmpty()) {
		Throwable current = toVisit.remove();
		boolean isFirstVisit = visited.add(current);
		if (isFirstVisit) {
			Throwable cause = current.getCause();
			if (cause != null) {
				toVisit.add(cause);
			}
			Collections.addAll(toVisit, current.getSuppressed());
		}
	}

	return List.copyOf(visited);
}

PoolSubpage(PoolSubpage<T> head, PoolChunk<T> chunk, int pageShifts, int runOffset, int runSize, int elemSize) {
    this.headIndex = head.headIndex;
    this.chunk = chunk;
    this.pageShifts = pageShifts;
    this.runOffset = runOffset;
    this.runSize = runSize;
    this.elemSize = elemSize;

    doNotDestroy = true;

    maxNumElems = numAvail = runSize / elemSize;
    int bitmapLength = maxNumElems >>> 6;
    if ((maxNumElems & 63) != 0) {
        bitmapLength ++;
    }
    this.bitmapLength = bitmapLength;
    bitmap = new long[bitmapLength];
    nextAvail = 0;

    lock = null;
    addToPool(head);
}

private long allocateSubpage(int sizeIdx, PoolSubpage<T> head) {
    //allocate a new run
    int runSize = calculateRunSize(sizeIdx);
    //runSize must be multiples of pageSize
    long runHandle = allocateRun(runSize);
    if (runHandle < 0) {
        return -1;
    }

    int runOffset = runOffset(runHandle);
    assert subpages[runOffset] == null;
    int elemSize = arena.sizeClass.sizeIdx2size(sizeIdx);

    PoolSubpage<T> subpage = new PoolSubpage<T>(head, this, pageShifts, runOffset,
            runSize(pageShifts, runHandle), elemSize);

    subpages[runOffset] = subpage;
    return subpage.allocate();
}

private long collapsePast(long handle) {
    for (;;) {
        int runOffset = runOffset(handle);
        int runPages = runPages(handle);

        long pastRun = getAvailRunByOffset(runOffset - 1);
        if (pastRun == -1) {
            return handle;
        }

        int pastOffset = runOffset(pastRun);
        int pastPages = runPages(pastRun);

        //is continuous
        if (pastRun != handle && pastOffset + pastPages == runOffset) {
            //remove past run
            removeAvailRun(pastRun);
            handle = toRunHandle(pastOffset, pastPages + runPages, 0);
        } else {
            return handle;
        }
    }
}

private long collapseNext(long handle) {
    for (;;) {
        int runOffset = runOffset(handle);
        int runPages = runPages(handle);

        long nextRun = getAvailRunByOffset(runOffset + runPages);
        if (nextRun == -1) {
            return handle;
        }

        int nextOffset = runOffset(nextRun);
        int nextPages = runPages(nextRun);

        //is continuous
        if (nextRun != handle && runOffset + runPages == nextOffset) {
            //remove next run
            removeAvailRun(nextRun);
            handle = toRunHandle(runOffset, runPages + nextPages, 0);
        } else {
            return handle;
        }
    }
}

public void expireTimeouts(long deadline) {
    HashedWheelTimeout timeout = head;

    // process all timeouts
    while (timeout != null) {
        HashedWheelTimeout next = timeout.next;
        if (timeout.remainingRounds <= 0) {
            if (timeout.deadline <= deadline) {
                timeout.expire();
            } else {
                // The timeout was placed into a wrong slot. This should never happen.
                throw new IllegalStateException(String.format(
                        "timeout.deadline (%d) > deadline (%d)", timeout.deadline, deadline));
            }
        } else if (!timeout.isCancelled()) {
            timeout.remainingRounds --;
        }
        timeout = next;
    }
}

public void removeAndFailAll(Throwable cause) {
    assert executor.inEventLoop();
    ObjectUtil.checkNotNull(cause, "cause");
    // It is possible for some of the failed promises to trigger more writes. The new writes
    // will "revive" the queue, so we need to clean them up until the queue is empty.
    for (PendingWrite write = head; write != null; write = head) {
        head = tail = null;
        size = 0;
        bytes = 0;
        while (write != null) {
            PendingWrite next = write.next;
            ReferenceCountUtil.safeRelease(write.msg);
            ChannelPromise promise = write.promise;
            recycle(write, false);
            safeFail(promise, cause);
            write = next;
        }
    }
    assertEmpty();
}

private void recycle(PendingWrite write, boolean update) {
    final PendingWrite next = write.next;
    final long writeSize = write.size;

    if (update) {
        if (next == null) {
            // Handled last PendingWrite so rest head and tail
            // Guard against re-entrance by directly reset
            head = tail = null;
            size = 0;
            bytes = 0;
        } else {
            head = next;
            size --;
            bytes -= writeSize;
            assert size > 0 && bytes >= 0;
        }
    }

    write.recycle();
    tracker.decrementPendingOutboundBytes(writeSize);
}

private void reportLeak() {
    if (!needReport()) {
        clearRefQueue();
        return;
    }

    // Detect and report previous leaks.
    for (;;) {
        DefaultResourceLeak<?> ref = (DefaultResourceLeak<?>) refQueue.poll();
        if (ref == null) {
            break;
        }

        if (!ref.dispose()) {
            continue;
        }

        String records = ref.getReportAndClearRecords();
        if (reportedLeaks.add(records)) {
            if (records.isEmpty()) {
                reportUntracedLeak(resourceType);
            } else {
                reportTracedLeak(resourceType, records);
            }

            LeakListener listener = leakListener;
            if (listener != null) {
                listener.onLeak(resourceType, records);
            }
        }
    }
}

private fun cacheResponseAge(): Long {
  val servedDate = this.servedDate
  val apparentReceivedAge =
    if (servedDate != null) {
      maxOf(0, receivedResponseMillis - servedDate.time)
    } else {
      0
    }

  val receivedAge =
    if (ageSeconds != -1) {
      maxOf(apparentReceivedAge, SECONDS.toMillis(ageSeconds.toLong()))
    } else {
      apparentReceivedAge
    }

  val responseDuration = maxOf(0, receivedResponseMillis - sentRequestMillis)
  val residentDuration = maxOf(0, nowMillis - receivedResponseMillis)
  return receivedAge + responseDuration + residentDuration
}
